const upsertTransaction = `-- name: UpsertTransaction :one
INSERT INTO transactions (id, account_id, plaid_transaction_id, date, authorized_date, name, merchant_name, amount, currency, category_id, category_source, category_confidence, pending, is_recurring)
VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
ON CONFLICT(plaid_transaction_id) DO UPDATE SET
    date                = excluded.date,
    authorized_date     = excluded.authorized_date,
    name                = excluded.name,
    merchant_name       = excluded.merchant_name,
    amount              = excluded.amount,
    pending             = excluded.pending,
    is_recurring        = excluded.is_recurring,
    category_id         = CASE WHEN transactions.category_source = 'uncategorized' THEN excluded.category_id         ELSE transactions.category_id         END,
    category_source     = CASE WHEN transactions.category_source = 'uncategorized' THEN excluded.category_source     ELSE transactions.category_source     END,
    category_confidence = CASE WHEN transactions.category_source = 'uncategorized' THEN excluded.category_confidence ELSE transactions.category_confidence END,
    updated_at          = CURRENT_TIMESTAMP
RETURNING id, account_id, plaid_transaction_id, date, authorized_date, name, merchant_name, amount, currency, category_id, category_source, category_confidence, pending, is_recurring, notes, created_at, updated_at
`

type UpsertTransactionParams struct {
	ID                 string  `json:"id"`
	AccountID          string  `json:"account_id"`
	PlaidTransactionID string  `json:"plaid_transaction_id"`
	Date               string  `json:"date"`
	AuthorizedDate     *string `json:"authorized_date"`
	Name               string  `json:"name"`
	MerchantName       *string `json:"merchant_name"`
	Amount             float64 `json:"amount"`
	Currency           string  `json:"currency"`
	CategoryID         *string `json:"category_id"`
	CategorySource     string  `json:"category_source"`
	CategoryConfidence *string `json:"category_confidence"`
	Pending            int64   `json:"pending"`
	IsRecurring        int64   `json:"is_recurring"`
}

func (q *Queries) UpsertTransaction(ctx context.Context, arg UpsertTransactionParams) (Transaction, error) {
	row := q.db.QueryRowContext(ctx, upsertTransaction,
		arg.ID,
		arg.AccountID,
		arg.PlaidTransactionID,
		arg.Date,
		arg.AuthorizedDate,
		arg.Name,
		arg.MerchantName,
		arg.Amount,
		arg.Currency,
		arg.CategoryID,
		arg.CategorySource,
		arg.CategoryConfidence,
		arg.Pending,
		arg.IsRecurring,
	)
	var i Transaction
	err := row.Scan(
		&i.ID,
		&i.AccountID,
		&i.PlaidTransactionID,
		&i.Date,
		&i.AuthorizedDate,
		&i.Name,
		&i.MerchantName,
		&i.Amount,
		&i.Currency,
		&i.CategoryID,
		&i.CategorySource,
		&i.CategoryConfidence,
		&i.Pending,
		&i.IsRecurring,
		&i.Notes,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}
